# Token-based authentication
def generate_token(tenant_id: str, role: str = 'user') -> str:
    payload = {
        'tenant_id': tenant_id,
        'role': role,
        'exp': datetime.utcnow() + timedelta(hours=24),
        'iat': datetime.utcnow()
    }
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')

def verify_token(token: str) -> Optional[Dict[str, Any]]:
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        logger.warning("Expired token attempt")
        return None
    except jwt.InvalidTokenError:
        logger.warning("Invalid token attempt")
        return None

def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            abort(401, description="Missing or invalid authorization header")
        
        token = auth_header.split(' ')[1]
        payload = verify_token(token)
        if not payload:
            abort(401, description="Invalid or expired token")
        
        request.tenant_id = payload['tenant_id']
        request.user_role = payload['role']
        return f(*args, **kwargs)
    return decorated_function

def validate_model_file(filename: str) -> bool:
    """Validate file extension against allowlist"""
    _, ext = os.path.splitext(filename.lower())
    if ext in BLOCKED_EXTENSIONS:
        logger.warning(f"Blocked dangerous extension: {ext}")
        return False
    return ext in ALLOWED_MODEL_FORMATS

def compute_file_hash(file_path: str) -> str:
    """Compute SHA256 hash of file for integrity verification"""
    sha256_hash = hashlib.sha256()
    with open(file_path, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest()

def load_model_secure(file_path: str, model_format: str) -> Any:
    """Load model using secure deserialization methods only"""
    try:
        if model_format == '.joblib':
            import joblib
            return joblib.load(file_path)
        elif model_format == '.h5':
            from tensorflow import keras
            return keras.models.load_model(file_path, compile=False)
        elif model_format == '.pt':
            import torch
            return torch.load(file_path, map_location='cpu', weights_only=True)
        elif model_format == '.onnx':
            import onnxruntime as ort
            return ort.InferenceSession(file_path)
        elif model_format == '.json':
            with open(file_path, 'r') as f:
                model_config = json.load(f)
            # Validate JSON structure
            if not isinstance(model_config, dict):
                raise ValueError("Invalid model configuration")
            return model_config
        else:
            raise ValueError(f"Unsupported model format: {model_format}")
    except Exception as e:
        logger.error(f"Model loading failed: {type(e).__name__}")
        raise ValueError("Failed to load model securely")

