    """Generate authentication token for tenant"""
    data = request.get_json()
    if not data or 'tenant_id' not in data or 'api_key' not in data:
        abort(400, description="Missing tenant_id or api_key")
    
    tenant_id = data['tenant_id']
    api_key = data['api_key']
    
    # Validate tenant credentials (in production, check against secure database)
    expected_key = os.environ.get(f'TENANT_{tenant_id}_KEY')
    if not expected_key or not hmac.compare_digest(api_key, expected_key):
        logger.warning(f"Failed authentication attempt for tenant: {tenant_id}")
        abort(401, description="Invalid credentials")
    
    token = generate_token(tenant_id)
    return jsonify({'token': token, 'expires_in': 86400})

